import API_PATHS from 'lib/http/apiPaths';

import useSelectOptions from './useSelectOptions';

export function useParcelOptions() {
  return useSelectOptions(API_PATHS.parcels, (parcel) => parcel.codigo_parcela);
}

export function usePersonOptions() {
  return useSelectOptions(API_PATHS.people, (person) => person.nombre_completo || person.email || `Persona ${person.id}`);
}

export function useUserOptions() {
  return useSelectOptions(API_PATHS.users, (user) => user.email || user.username || `Usuario ${user.id}`);
}

export function optionLabelByValue(options, value) {
  return options.find((opt) => String(opt.value) === String(value))?.label || value || '-';
}
